import{_ as r,o as p,c as a,ae as o}from"./chunks/framework.AOaeJVPC.js";const s=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/我的项目/回答/低代码平台-面试清单.md","filePath":"note/我的项目/回答/低代码平台-面试清单.md"}'),t={name:"note/我的项目/回答/低代码平台-面试清单.md"};function n(i,e,d,c,m,_){return p(),a("div",null,[...e[0]||(e[0]=[o('<p>项目介绍版</p><p>BT低代码平台是一个面向内部运营的自研低代码平台，支持营销活动页和落地页的可视化搭建、发布和版本管理，累计支撑了 200+ 线上页面交付，简单页面交付周期从原来的 2 周 缩短到 2-3 天。</p><p>我在这个项目里担任前端负责人角色，主要负责三块：</p><ul><li>第一块是平台架构设计，采用 Monorepo + 微内核 + 插件化，把 Schema 协议、插件注册机制、渲染上下文、命令系统 这些稳定的平台级通用能力沉淀到内核里，把 物料、属性设置器、数据源适配、调试面板、发布扩展 这些高频变化能力做成插件，保证平台可持续扩展。</li><li>第二块是核心引擎建设，包括 Schema、Renderer、拖拽编排引擎。Schema 不是普通组件树 JSON，而是平台内部的统一协议，结构关系和节点详情分离，方便局部更新、调试和历史回放；Renderer 做成协议驱动的通用执行层，新增物料主要靠注册，不需要频繁改渲染内核；拖拽这块重点解决复杂嵌套布局下的目标容器命中和放置位置判断，采用 射线检测 + 最近父容器回溯，并通过缓存几何信息、requestAnimationFrame 合帧、局部更新和滚动增量修正提升拖拽性能。</li><li>第三块是表达式和调试体系，基于 CodeMirror 6 做变量编辑器，支持补全、错误提示和上下文感知，运行时通过受控上下文和沙箱限制危险能力，同时设计了业务层、实施层、技术层三层调试能力，帮助定位表达式、数据绑定和渲染链路问题。</li></ul><p>如果只选一个最体现架构能力的设计决策，我会选 Schema 协议驱动 + Renderer/物料解耦。因为它把平台从“功能集合”变成了“协议驱动系统”，直接决定了后续扩展性、维护成本和演进上限。</p><h2 id="_3分钟背诵稿" tabindex="-1">3分钟背诵稿 <a class="header-anchor" href="#_3分钟背诵稿" aria-label="Permalink to &quot;3分钟背诵稿&quot;">​</a></h2><p>BT 低代码平台是一个面向内部运营的自研低代码平台，主要用于搭建 H5 和 PC 的营销活动页、落地页，支持可视化拖拽、变量配置、事件编排、发布和版本管理。这个平台累计支撑了 200 多个线上页面交付，简单页面的交付周期从原来的 2 周缩短到了 2 到 3 天。</p><p>我在这个项目里主要负责三块。第一块是平台架构设计，我们采用了 Monorepo 加微内核加插件化的方式。原因是低代码平台天然是高扩展系统，除了基础画布和渲染能力，后面还会不断增加物料、设置器、数据源接入、调试能力、发布能力，所以不适合做成简单单体。我们把 Schema 协议、插件注册机制、渲染上下文、命令系统这些稳定的平台级能力放到内核里，把物料、设置器、调试面板、数据源适配这类高频变化能力做成插件，这样平台更容易扩展和治理。</p><p>第二块是核心引擎建设，包括 Schema、Renderer 和拖拽编排引擎。Schema 我们没有直接用一棵普通组件树 JSON，而是专门设计成平台统一协议，把结构关系和节点详情拆开。这样做的好处是修改节点时不需要深度遍历整棵树，局部更新粒度更小，也更方便后面做版本迁移、历史 diff、调试和校验。Renderer 则做成协议驱动的通用执行层，它接收的是 Schema、物料注册信息和运行时上下文，自己只负责解析节点、遍历结构、计算变量和事件，再根据节点类型去注册中心找到对应物料进行渲染。这样新增物料时，更多是按协议注册，而不需要频繁改渲染内核。</p><p>第三块是拖拽编排引擎和表达式系统。拖拽这块最难的是复杂嵌套布局下的命中和放置问题，因为普通拖拽方案只能知道鼠标命中了哪个 DOM，但低代码真正要解决的是应该放到哪个容器，以及是 before、after 还是 inside。我们采用了射线检测加最近父容器回溯的方式，先找到当前鼠标下的节点，再沿父链回溯到最近合法容器，最后结合布局方向和阈值判断插入语义。性能上，我们在拖拽开始前缓存节点几何信息和容器元数据，拖拽过程中通过 requestAnimationFrame 合帧，只做命中检测、位置判断和局部 UI 更新，滚动时优先用 scroll delta 修正缓存，而不是每帧都重新查 DOM，这样复杂页面下拖拽帧率能稳定很多。</p><p>表达式系统这块，我们基于 CodeMirror 6 做了变量编辑器，因为低代码里的表达式不是普通文本，它会引用页面变量、组件上下文和接口数据，如果只是 textarea，用户写复杂表达式时体验会很差。运行时我们又做了一层受控执行环境，通过白名单上下文和 Proxy 限制危险能力访问，同时配合业务层、配置层、技术层三层调试能力，帮助定位表达式、变量绑定和渲染链路问题。</p><p>如果只选一个最体现我架构能力的设计决策，我会选 Schema 协议驱动这件事。因为它把平台从一个功能集合，变成了一个真正可扩展、可演进的协议驱动系统。”</p><p>高频问答版</p><p>为什么要做 Monorepo + 微内核 + 插件化 低代码平台天然是高扩展系统，不适合简单单体。Monorepo 解决多包协同、类型共享和统一构建问题；内核承接稳定的平台级能力，插件承接高频变化和业务扩展。</p><p>内核和插件怎么划分 跨模块复用、平台级、稳定的能力进内核，比如 Schema 协议、插件生命周期、命令系统、事件总线、渲染上下文；高频变化、业务化、可替换能力做插件，比如 物料、设置器、数据源适配、发布目标、调试面板。</p><p>为什么不用普通组件树 JSON，非要设计 Schema 因为 Schema 不只是存页面，而是编辑器、Renderer、发布、校验、调试共用的正式协议。结构关系和节点详情分离后，局部更新、版本迁移、历史 diff、多人协作都会更清晰。</p><p>Renderer 怎么和 Schema 解耦 Schema 负责描述，物料 负责实现，Renderer 负责解释执行。Renderer 根据 node.type 去物料注册中心取组件定义和渲染适配器，所以新增物料主要靠注册，不靠改渲染内核。</p><p>为什么普通拖拽方案不够用 普通方案只知道鼠标命中了哪个 DOM，但低代码真正要解决的是“应该放到哪个容器、能不能放、是 before/after/inside 哪一种”。复杂嵌套下鼠标经常命中叶子节点，不等于真正目标容器。</p><p>射线检测 + 最近父容器回溯 是怎么做的 先根据指针位置命中当前可见 DOM，再映射回低代码节点，沿父链回溯到最近一个合法可放置容器，最后结合布局方向和阈值判断 before / after / inside。</p><p>拖拽为什么最难优化 因为它同时是 高频输入 + 实时计算 + 即时渲染反馈。拖拽过程中每一帧都可能做命中检测、插入位置计算、预览层更新和自动滚动判断，用户对卡顿非常敏感。</p><p>拖拽性能怎么做 拖拽开始前预计算节点几何信息和容器元数据；拖拽过程中用 requestAnimationFrame 合帧，只做命中检测、插入判断和局部 UI 更新；滚动时优先用 scroll delta 修正缓存；Schema 持久化、历史记录、埋点和复杂校验放到 drop 后或异步处理。</p><p>为什么用 CodeMirror 6 做变量编辑器 表达式不是普通文本，会引用页面变量、组件上下文和接口数据，需要补全、错误提示和上下文感知。CodeMirror 6 更轻、扩展性更好，适合嵌入式表达式编辑场景。</p><p>沙箱的边界是什么 它是前端侧的受控执行环境，不是真正强隔离沙箱。目标是限制危险能力、降低副作用和运行风险，不是宣称绝对安全。</p><p>片段插槽和自定义组件怎么划分 片段插槽解决标准物料里的局部差异化，范围小、接入快；自定义组件承接完整、可复用的能力，适用于独立样式、事件、状态和数据源都更复杂的场景。</p><p>如果重做一次，你会改什么 我会更早做 状态分层 + 统一 operation/command 层，把 持久化 Schema、编辑器临时态、运行时状态 彻底拆开，让撤销重做、历史回放、调试追踪和多人协作更容易演进。</p><p>高频金句</p><p>低代码平台本质上是一个高扩展的协议驱动系统。 Schema 不只是页面数据，而是平台内部的通用语言。 Renderer 不是写死业务组件，而是解释协议的执行层。 拖拽最难，不是逻辑最多，而是计算密集和实时反馈绑在了一起。 片段插槽解决局部差异，自定义组件沉淀完整能力。</p>',27)])])}const S=r(t,[["render",n]]);export{s as __pageData,S as default};
